#include "controller.h"

#define TEST_CONTROLLER_IMPLEMENTATION 1

static void test_controller_init(void)
{
    controller_t controller;
    controller_init(&controller);

    assert(controller->filter_on == false);
    assert(controller->drain_open == false);
    assert(controller->state == CONTROLLER_STATE_SAFE_IDLE);
    assert(controller->has_valid_turbidity == false);
    assert(controller->has_valid_level == false);
    assert(controller->clear_streak_count == 0);
    assert(controller->settling_started_ms == 0U);
}

static void test_controller_boot_leaves_safe_idle(void)
{
    controller_t controller;
    controller_init(&controller);

    // Should be in SAFE_IDLE state with filter off, drain closed
    assert(controller->filter_on == false);
    assert(controller->drain_open == false);
    assert(controller->state == CONTROLLER_STATE_SAFE_IDLE);
}

static void test_controller_boot_with_no_valid_data(void)
{
    controller_t controller;
    controller_init(&controller);

    // Should remain in SAFE_IDLE state even with no valid data
    assert(controller->filter_on == false);
    assert(controller->drain_open == false);
    assert(controller->state == CONTROLLER_STATE_SAFE_IDLE);
}

static void test_controller_safe_idle_stays_safe_idle(void)
{
    controller_t controller;
    controller_init(&controller);

    // Keep in SAFE_IDLE state
